from enum import Enum
from dataclasses import dataclass

class ClinicalPurpose(str, Enum):
    MEDICATION_CHECK   = "medication_check"
    NOTE_SUMMARISATION = "note_summarisation"
    BILLING_CODE       = "billing_code"
    APPOINTMENT_SCHED  = "appointment_scheduling"

# Map purpose → PHI fields permitted in prompt
_MINIMUM_NECESSARY: dict[ClinicalPurpose, set[str]] = {
    ClinicalPurpose.MEDICATION_CHECK:   {"medication_list", "allergies", "weight_kg"},
    ClinicalPurpose.NOTE_SUMMARISATION: {"note_text"},       # no demographics needed
    ClinicalPurpose.BILLING_CODE:       {"icd_codes", "cpt_codes", "note_text"},
    ClinicalPurpose.APPOINTMENT_SCHED:  {"preferred_times", "provider_id"},
}

@dataclass
class PHIPayload:
    fields: dict[str, str]

def enforce_minimum_necessary(
    payload: PHIPayload, purpose: ClinicalPurpose
) -> dict[str, str]:
    """Strip fields not required for the given clinical purpose.""""
    allowed = _MINIMUM_NECESSARY.get(purpose, set())
    stripped = {k: v for k, v in payload.fields.items() if k in allowed}
    blocked  = set(payload.fields) - allowed
    if blocked:
        import logging
        logging.info("Minimum-necessary: blocked fields %s for purpose %s", blocked, purpose)
    return stripped
